mapper.select:
SELECT R.ROLE_ID, COUNT(UR.LOGINID) AS ASSIGNED_CNT, #{totalCnt} AS TOTAL_CNT FROM T_WMS_ROLE R LEFT JOIN T_WMS_USER_ROLE UR ON UR.ROLE_ID = R.ROLE_ID AND UR.USEYN = 'Y' AND UR.LOGINID IN
#{id}
WHERE R.USEYN = 'Y' AND R.ROLE_ID <> 'ADMIN' GROUP BY R.ROLE_ID, R.SORTING ORDER BY R.SORTING

WITH USER_LIST AS ( SELECT COLUMN_VALUE AS USER_ID FROM TABLE( SYS.ODCIVARCHAR2LIST(
#{id}
) ) ), ROLE_MENU AS ( SELECT U.USER_ID, P.MENU_CODE FROM USER_LIST U JOIN T_WMS_USER_ROLE UR ON UPPER(UR.LOGINID) = UPPER(U.USER_ID) AND UR.USEYN = 'Y' JOIN T_WMS_ROLE_PERMISSION P ON P.ROLE_ID = UR.ROLE_ID AND P.USEYN = 'Y' ), OVR AS ( SELECT UPPER(LOGINID) AS USER_ID, MENU_CODE, USEYN FROM T_WMS_USER_PERMISSION_OVERRIDE ), EFFECTIVE AS ( SELECT U.USER_ID, M.MENU_CODE, CASE WHEN O.MENU_CODE IS NOT NULL THEN O.USEYN WHEN R.MENU_CODE IS NOT NULL THEN 'Y' ELSE 'N' END AS USEYN FROM USER_LIST U JOIN T_WMS_MENU M ON M.USEYN = 'Y' LEFT JOIN ROLE_MENU R ON UPPER(R.USER_ID) = UPPER(U.USER_ID) AND R.MENU_CODE = M.MENU_CODE LEFT JOIN OVR O ON O.USER_ID = UPPER(U.USER_ID) AND O.MENU_CODE = M.MENU_CODE ) SELECT MENU_CODE, CASE WHEN SUM(CASE WHEN USEYN = 'Y' THEN 1 ELSE 0 END) = COUNT(*) THEN 'Y' WHEN SUM(CASE WHEN USEYN = 'Y' THEN 1 ELSE 0 END) = 0 THEN 'N' ELSE 'M' END AS STATE FROM EFFECTIVE GROUP BY MENU_CODE ORDER BY MENU_CODE

mapper.update:
UPDATE T_WMS_USER_ROLE
SET USEYN = 'N'
WHERE USER_ID = #{userId}
AND ROLE_ID = #{roleId}
AND USEYN = 'Y'

